const defaultPosition = [-75.379143, 39.831200]
const mapContainerStyle = {
  position: 'absolute',
  left: 0,
  right: 0,
  top: 0,
  bottom: 0,
}

const MapPlaygroundExample = () => {
  const [mapInstance, setMapInstance] = useState(null)
  const mapContainerRef = useRef(null)

  const handleZoomIn = (map) => map?.zoomIn({ ...mapTheme.zoomConfig })
  const handleZoomOut = (map) => map?.zoomOut({ ...mapTheme.zoomConfig })
  const handleFlyTo = (map) => map?.flyTo({
    center: defaultPosition,
    ...mapTheme.flyToConfig,
  })

  useEffect(() => {
    if (!mapContainerRef.current) return undefined

    const map = new maplibregl.Map({
      container: mapContainerRef.current,
      center: defaultPosition,
      ...mapTheme.mapConfig,
    })

    map.on('load', ({ target }) => {
      new maplibregl.Marker({ color: mapTheme.marker })
        .setLngLat(defaultPosition)
        .setPopup(
          new maplibregl.Popup({ closeButton: false }).setHTML(
            '<h4 class="pb_title_kit pb_title_4">Hello World!</h4>'
          )
        )
        .addTo(target)

      target.scrollZoom.disable()
      target.addControl(new maplibregl.AttributionControl({ compact: true }))
      setMapInstance(target)
    })

    return () => map.remove()
  }, [])

  return {{component}}
}

<MapPlaygroundExample />

